// n8n already splits array items — just build the Ollama payload per email
// so special characters in email body don't break the JSON
const items = $input.all();
const results = [];

for (const item of items) {
  const email = item.json;
  if (!email.id || !email.sender) continue;

  const payload = {
    model: "llama3.2",
    stream: false,
    messages: [
      {
        role: "system",
        content: "You are an AI approval agent for an organization. Analyze the email and respond with ONLY a valid JSON object — no markdown, no code fences, no explanation. Required fields: title (string max 80 chars), category (one of exactly: Room Booking, Club Permission, IT Access, Budget Approval, Event Approval, Other), department (string, guess from context or Unknown), urgency (one of: low, normal, high, critical), risk_score (number 0-100), risk_level (one of: low, medium, high — low=0-34 medium=35-69 high=70-100), ai_summary (2-3 sentence summary), key_points (array of up to 5 strings), sentiment (one of: positive, neutral, negative), ai_recommendation (one of: auto_approve, review, escalate), ai_confidence (number 0-100), action_required (boolean)"
      },
      {
        role: "user",
        content: "Analyze this email:\nFrom: " + email.sender + "\nSubject: " + email.subject + "\nBody: " + email.body
      }
    ]
  };

  results.push({
    json: {
      email_id: email.id,
      sender: email.sender,
      subject: email.subject,
      body: email.body,
      ollama_payload: JSON.stringify(payload)
    }
  });
}

return results;

const ollamaResponse = $input.first().json;
const email = $('Build Ollama Payload').first().json;

const raw = ollamaResponse.message?.content?.trim() || '';

// Parse Ollama response safely
let ai;
try {
  const clean = raw.replace(/^```json\n?|^```\n?|\n?```$/g, '').trim();
  ai = JSON.parse(clean);
} catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  try { ai = match ? JSON.parse(match[0]) : null; } catch(e2) { ai = null; }
  if (!ai) ai = {};
}

// Validate fields
const validCategories = ['Room Booking','Club Permission','IT Access','Budget Approval','Event Approval','Other'];
const validUrgency = ['low','normal','high','critical'];
const validRecommendations = ['auto_approve','review','escalate'];
const validSentiments = ['positive','neutral','negative'];

const riskScore = Math.min(100, Math.max(0, Number(ai.risk_score) || 50));

// Derive status from risk score + recommendation
let status;
if (ai.ai_recommendation === 'auto_approve' || riskScore < 35) status = 'auto_approved';
else if (ai.ai_recommendation === 'escalate' || riskScore >= 70) status = 'escalated';
else status = 'pending';

// Always derive risk_level from score to keep it consistent
let riskLevel;
if (riskScore < 35) riskLevel = 'low';
else if (riskScore < 70) riskLevel = 'medium';
else riskLevel = 'high';

const recommendation = validRecommendations.includes(ai.ai_recommendation) ? ai.ai_recommendation : 'review';
const sentiment = validSentiments.includes(ai.sentiment) ? ai.sentiment : 'neutral';
const keyPoints = Array.isArray(ai.key_points) ? ai.key_points : [];
const aiSummary = ai.ai_summary || '';

return [{
  json: {
    // Carry forward for later nodes
    email_id: email.email_id,
    sender: email.sender,
    subject: email.subject,
    body: email.body,
    risk_score: riskScore,
    risk_level: riskLevel,
    status: status,
    recommendation: recommendation,
    ai_summary: aiSummary,
    key_points: keyPoints,
    sentiment: sentiment,
    action_required: Boolean(ai.action_required),
    ai_confidence: Math.min(100, Math.max(0, Number(ai.ai_confidence) || 50)),

    // request row payload
    request_payload: JSON.stringify({
      email_id: email.email_id,
      title: (ai.title || email.subject || 'Untitled Request').slice(0, 80),
      category: validCategories.includes(ai.category) ? ai.category : 'Other',
      description: email.body,
      department: ai.department || 'Unknown',
      urgency: validUrgency.includes(ai.urgency) ? ai.urgency : 'normal',
      requester_name: email.sender.split('@')[0].replace(/[._]/g, ' '),
      requester_email: email.sender,
      risk_score: riskScore,
      risk_level: riskLevel,
      ai_summary: aiSummary,
      ai_recommendation: recommendation,
      ai_confidence: Math.min(100, Math.max(0, Number(ai.ai_confidence) || 50)),
      status: status
    }),

    // email_summaries row payload
    summary_payload: JSON.stringify({
      email_id: email.email_id,
      summary: aiSummary,
      key_points: keyPoints,
      sentiment: sentiment,
      action_required: Boolean(ai.action_required)
    })
  }
}];

const savedRequest = $input.first().json;
const parsed = $('Parse Ollama Response').first().json;

const requestId = Array.isArray(savedRequest) ? savedRequest[0]?.id : savedRequest?.id;

let action;
if (parsed.status === 'auto_approved') action = 'auto_approved';
else if (parsed.status === 'escalated') action = 'escalated';
else action = 'risk_scored';

return [{
  json: {
    request_id: requestId,
    email_id: parsed.email_id,
    action: action,
    actor_name: 'AI System',
    notes: 'Risk scored at ' + parsed.risk_score + ' (' + parsed.risk_level + ') — ' + parsed.status,
    metadata: JSON.stringify({
      risk_score: parsed.risk_score,
      risk_level: parsed.risk_level,
      recommendation: parsed.recommendation,
      sentiment: parsed.sentiment,
      status: parsed.status
    })
  }
}];
